/// character types
enum OnigEncCtype {
  ONIGENC_CTYPE_NEWLINE(0),
  ONIGENC_CTYPE_ALPHA(1),
  ONIGENC_CTYPE_BLANK(2),
  ONIGENC_CTYPE_CNTRL(3),
  ONIGENC_CTYPE_DIGIT(4),
  ONIGENC_CTYPE_GRAPH(5),
  ONIGENC_CTYPE_LOWER(6),
  ONIGENC_CTYPE_PRINT(7),
  ONIGENC_CTYPE_PUNCT(8),
  ONIGENC_CTYPE_SPACE(9),
  ONIGENC_CTYPE_UPPER(10),
  ONIGENC_CTYPE_XDIGIT(11),
  ONIGENC_CTYPE_WORD(12),

  /// alpha || digit
  ONIGENC_CTYPE_ALNUM(13),
  ONIGENC_CTYPE_ASCII(14);

  final int value;
  const OnigEncCtype(this.value);

  static OnigEncCtype fromValue(int value) => switch (value) {
    0 => ONIGENC_CTYPE_NEWLINE,
    1 => ONIGENC_CTYPE_ALPHA,
    2 => ONIGENC_CTYPE_BLANK,
    3 => ONIGENC_CTYPE_CNTRL,
    4 => ONIGENC_CTYPE_DIGIT,
    5 => ONIGENC_CTYPE_GRAPH,
    6 => ONIGENC_CTYPE_LOWER,
    7 => ONIGENC_CTYPE_PRINT,
    8 => ONIGENC_CTYPE_PUNCT,
    9 => ONIGENC_CTYPE_SPACE,
    10 => ONIGENC_CTYPE_UPPER,
    11 => ONIGENC_CTYPE_XDIGIT,
    12 => ONIGENC_CTYPE_WORD,
    13 => ONIGENC_CTYPE_ALNUM,
    14 => ONIGENC_CTYPE_ASCII,
    _ => throw ArgumentError('Unknown value for OnigEncCtype: $value'),
  };
}

